--
-- Create or alter view [SCore].[EntityPropertyGroupsV]
--
GO
CREATE OR ALTER VIEW	[SCore].[EntityPropertyGroupsV]
             --WITH SCHEMABINDING
AS
SELECT	epg.ID,
		epg.RowStatus,
		epg.RowVersion,
		epg.Guid,
		epg.Name,
		epg.IsHidden,
		epg.SortOrder,
		epg.LanguageLabelID,
		epg.EntityTypeID,
		epg.PropertyGroupLayoutID,
		epg.IsCollapsable,
		epg.IsDefaultCollapsed,
		epg.IsDefaultCollapsed_Mobile,
		epg.ShowOnMobile
FROM	Score.[EntityPropertyGroups] epg
WHERE	(epg.[RowStatus] NOT IN (0, 254))
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

