--
-- Create or alter function [SUserInterface].[tvf_GridViewDefinitions]
--
GO
CREATE OR ALTER FUNCTION [SUserInterface].[tvf_GridViewDefinitions]
  (
    @Id           INT,
    @GridViewCode NVARCHAR(20),
    @GridCode     NVARCHAR(30),
    @UserId       INT
  )
RETURNS TABLE
   --WITH SCHEMABINDING
AS
  RETURN SELECT
		gvd.ID,
		gvd.Code,
		gvd.Guid,
		olfu.LabelPlural Name,
		gvd.RowVersion,
		gvd.GridDefinitionId,
		gvd.SqlQuery,
		gvd.DetailPageUri,
		gvd.DefaultSortColumnName,
		gvd.DisplayGroupName,
		gvd.DisplayOrder,
		gvd.MetricSqlQuery,
		gvd.ShowMetric,
		gvd.IsDetailWindowed,
		i.Name			 AS DrawerIconCss,
		gvd.IsDefaultSortDescending,
		gvd.AllowNew,
		gvd.AllowExcelExport,
		gvd.AllowPdfExport,
		gvd.AllowCsvExport,
		et.Guid			 AS EntityTypeGuid,
		gvt.Guid		 AS GridViewTypeGuid,
		gvd.GridViewTypeId,
		gvd.AllowBulkChange,
		gvd.ShowOnMobile
FROM
		SUserInterface.GridViewDefinitions AS gvd
JOIN
		SUserInterface.Icons i ON gvd.DrawerIconId = i.ID
JOIN
		SUserInterface.GridViewTypes gvt ON (gvt.ID = gvd.GridViewTypeId)
JOIN
		SCore.EntityTypes AS et ON (gvd.EntityTypeID = et.ID)
OUTER APPLY
		SCore.ObjectLabelForUser(gvd.LanguageLabelID, @UserId) olfu
WHERE
		(
				(gvd.ID = @Id)
				OR (
						(EXISTS
							(
								SELECT	1
								FROM	SUserInterface.GridDefinitions AS gd
								WHERE	(gd.ID = gvd.GridDefinitionId)
									AND (gd.RowStatus NOT IN (0, 254))
									AND	(gd.Code = @GridCode)
							)
						)
						AND (
								(gvd.Code = @GridViewCode)
								OR (@GridViewCode = N'')
						)
				)
		)
		AND (gvd.RowStatus NOT IN (0, 254))		
		AND (EXISTS
		(
			SELECT
					1
			FROM
					SCore.ObjectSecurityForUser_CanRead(gvd.Guid, @UserId) oscr
		)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[tvf_PropertyGroupsForEntityType]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_PropertyGroupsForEntityType]
	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE
            --WITH SCHEMABINDING
AS
RETURN SELECT		pg.RowStatus,
					pg.RowVersion,
					pg.Guid,
					pg.Name,
					e.Guid	 AS EntityTypeGuid,
					ll.Guid	 AS LanguageLabelGuid,
					pgl.Guid AS PropertyGroupLayoutGuid,
					pgl.Name AS PropertyGroupLayout,
					pg.IsHidden,
					pg.SortOrder,
					pg.IsCollapsable,
					pg.IsDefaultCollapsed,
					pg.IsDefaultCollapsed_Mobile,
					pg.ShowOnMobile,
					os.CanRead,
					os.CanWrite,
					ISNULL (   lt.Label,
							   N''
						   ) AS Label
	   FROM			SCore.EntityPropertyGroupsV	  AS pg
	   JOIN			SCore.LanguageLabelsV		  AS ll ON (ll.ID = pg.LanguageLabelID)
	   JOIN			SUserInterface.PropertyGroupLayouts pgl ON (pgl.ID = pg.PropertyGroupLayoutID)
	   LEFT JOIN	SCore.EntityTypesV			  AS e ON (pg.EntityTypeID = e.ID)
	   OUTER APPLY	SCore.ObjectSecurityForUser (	pg.Guid,
													@UserId
												) AS os
	   OUTER APPLY	SCore.ObjectLabelForUser (	 pg.LanguageLabelID,
												 @UserId
											 ) AS lt
	   WHERE		(ISNULL(e.Guid, '00000000-0000-0000-0000-000000000000') = @Guid)
				 OR (pg.ID	= -1);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SCore].[NonActivityEventsUpsert]
--
GO
CREATE OR ALTER PROCEDURE [SCore].[NonActivityEventsUpsert]
(
	@EventName VARCHAR(100),
	@StartTime DATETIME,
	@EndTime DATETIME,
	@TeamId SMALLINT,
	@MemberId SMALLINT,
	@Guid UNIQUEIDENTIFIER
) 
AS
BEGIN


	DECLARE	@IsInsert bit
	EXEC SCore.UpsertDataObject @Guid = @Guid,					-- uniqueidentifier
							@SchemeName = N'SCore',				-- nvarchar(255)
							@ObjectName = N'NonActivityEvents',				-- nvarchar(255)
							@IncludeDefaultSecurity = 0,
							@IsInsert = @IsInsert OUTPUT	-- bit


	IF (@IsInsert = 1)
    BEGIN 
        INSERT  SCore.NonActivityEvents 
        (
            RowStatus,
            Guid,
			EventName,
			StartTime,
			EndTime,
			TeamId,
			MemberId
			
        )
        VALUES
        (
            1,
            @Guid,
			@EventName,
            @StartTime,
			@EndTime,
			@TeamId,
			@MemberId
        )
    END
    ELSE
    BEGIN 
        UPDATE  SCore.NonActivityEvents
        SET     RowStatus = 1,
                EventName = @EventName,
				StartTime = @StartTime,
				EndTime = @EndTime,
				TeamId = @TeamId,
				MemberId = @MemberId
        WHERE   ([Guid] = @Guid)
    END


END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SUserInterface].[GridViewDefinitionUpsert]
--
GO
CREATE OR ALTER PROCEDURE [SUserInterface].[GridViewDefinitionUpsert]
  (
    @Code                    NVARCHAR(20),
    @RowStatus               TINYINT,
    @GridDefinitionGuid      UNIQUEIDENTIFIER,
    @DetailPageUri           NVARCHAR(250),
    @SqlQuery                NVARCHAR(MAX),
    @DefaultSortColumnName   NVARCHAR(250),
    @SecurableCode           NVARCHAR(20),
    @DisplayOrder            INT,
    @DisplayGroupName        NVARCHAR(50),
    @MetricSqlQuery          NVARCHAR(MAX),
    @ShowMetric              BIT,
    @IsDetailWindowed        BIT,
    @EntityTypeGuid          UNIQUEIDENTIFIER,
    @MetricTypeGuid          UNIQUEIDENTIFIER,
    @MetricMin               INT,
    @MetricMax               INT,
    @MetricMinorUnit         INT,
    @MetricMajorUnit         INT,
    @MetricStartAngle        INT,
    @MetricEndAngle          INT,
    @MetricReversed          BIT,
    @MetricRange1Min         DECIMAL(18, 0),
    @MetricRange1Max         DECIMAL(18, 0),
    @MetricRange1ColourHex   NVARCHAR(10),
    @MetricRange2Min         DECIMAL(18, 0),
    @MetricRange2Max         DECIMAL(18, 0),
    @MetricRange2ColourHex   NVARCHAR(10),
    @IsDefaultSortDescending BIT,
    @AllowNew                BIT,
    @AllowExcelExport        BIT,
    @AllowPdfExport          BIT,
    @AllowCsvExport          BIT,
    @LanguageLabelGuid       UNIQUEIDENTIFIER,
    @DrawerIconGuid          UNIQUEIDENTIFIER,
	@GridViewTypeGuid		 UNIQUEIDENTIFIER,
	@AllowBulkChange		BIT,
    @Guid                    UNIQUEIDENTIFIER OUT,
	@ShowOnMobile			BIT
  )
AS
  BEGIN
    DECLARE @LanguageLabelID  INT = -1,
            @GridDefinitionID INT,
            @EntityTypeID     INT,
            @MetricTypeID     INT = -1,
			@GridViewTypeID		INT = -1,
            @DrawerIconId     INT = -1;



    SELECT
            @GridDefinitionID = ID
    FROM
            SUserInterface.GridDefinitions
    WHERE
            ([Guid] = @GridDefinitionGuid)

    SELECT
            @EntityTypeID = ID
    FROM
            SCore.EntityTypes
    WHERE
            ([Guid] = @EntityTypeGuid)

    SELECT
            @MetricTypeID = ID
    FROM
            SUserInterface.MetricTypes
    WHERE
            ([Guid] = @MetricTypeGuid)

    SELECT
            @LanguageLabelID = ID
    FROM
            SCore.LanguageLabels ll
    WHERE
            (Guid = @LanguageLabelGuid)

    SELECT
            @DrawerIconId = ID
    FROM
            SUserInterface.Icons i
    WHERE
            (Guid = @DrawerIconGuid)

	SELECT	
			@GridViewTypeID = ID
	FROM	
			SUserInterface.GridViewTypes gvt
	WHERE	
			(gvt.Guid = @GridViewTypeGuid)

    DECLARE @IsInsert BIT
    EXEC SCore.UpsertDataObject
      @Guid       = @Guid,					-- uniqueidentifier
      @SchemeName = N'SUserInterface',				-- nvarchar(255)
      @ObjectName = N'GridViewDefinitions',				-- nvarchar(255)
      @IsInsert   = @IsInsert OUTPUT	-- bit

    IF (@IsInsert = 1)
      BEGIN
        DECLARE @ID INT

        INSERT SUserInterface.GridViewDefinitions
              (
                [Guid],
                LanguageLabelId,
                [RowStatus],
                [Code],
                [GridDefinitionId],
                [DetailPageUri],
                [SqlQuery],
                [DefaultSortColumnName],
                [SecurableCode],
                [DisplayOrder],
                [DisplayGroupName],
                [MetricSqlQuery],
                [ShowMetric],
                [IsDetailWindowed],
                [EntityTypeID],
                [MetricTypeID],
                [MetricMin],
                [MetricMax],
                [MetricMinorUnit],
                [MetricMajorUnit],
                [MetricStartAngle],
                [MetricEndAngle],
                [MetricReversed],
                [MetricRange1Min],
                [MetricRange1Max],
                MetricRange1ColourHex,
                MetricRange2Min,
                MetricRange2Max,
                MetricRange2ColourHex,
                DrawerIconId,
                IsDefaultSortDescending,
                AllowNew,
                AllowExcelExport,
                AllowPdfExport,
                AllowCsvExport,
				GridViewTypeId,
				AllowBulkChange,
				ShowOnMobile
              )
        VALUES
                (
                  @Guid,
                  @LanguageLabelID,
                  1,
                  @Code,
                  @GridDefinitionID,
                  @DetailPageUri,
                  @SqlQuery,
                  @DefaultSortColumnName,
                  @SecurableCode,
                  @DisplayOrder,
                  @DisplayGroupName,
                  @MetricSqlQuery,
                  @ShowMetric,
                  @IsDetailWindowed,
                  @EntityTypeID,
                  @MetricTypeID,
                  @MetricMin,
                  @MetricMax,
                  @MetricMinorUnit,
                  @MetricMajorUnit,
                  @MetricStartAngle,
                  @MetricEndAngle,
                  @MetricReversed,
                  @MetricRange1Min,
                  @MetricRange1Max,
                  @MetricRange1ColourHex,
                  @MetricRange2Min,
                  @MetricRange2Max,
                  @MetricRange2ColourHex,
                  @DrawerIconId,
                  @IsDefaultSortDescending,
                  @AllowNew,
                  @AllowExcelExport,
                  @AllowPdfExport,
                  @AllowCsvExport,
				  @GridViewTypeID,
				  @AllowBulkChange,
				  @ShowOnMobile
                )

        SELECT
                @ID = SCOPE_IDENTITY()


        DECLARE @NewID1    UNIQUEIDENTIFIER = NEWID(),
                @NewID2    UNIQUEIDENTIFIER = NEWID(),
				@IdLanguageLabel INT, 
				@GuidLanguageLabel INT,
                @IsInsert2 BIT;

		SELECT	@IdLanguageLabel = ll.ID
		FROM	SCore.LanguageLabels AS ll 
		WHERE	ll.Name = N'#_grid_column'

		SELECT	@GuidLanguageLabel = ll.ID
		FROM	SCore.LanguageLabels AS ll 
		WHERE	ll.Name = N'Guid_grid_column'

        EXEC SCore.UpsertDataObject
          @Guid       = @NewID1,
          @SchemeName = N'SUserInterface',
          @ObjectName = N'GridViewColumnDefinitions',
          @IsInsert   = @IsInsert2

        EXEC SCore.UpsertDataObject
          @Guid       = @NewID2,
          @SchemeName = N'SUserInterface',
          @ObjectName = N'GridViewColumnDefinitions',
          @IsInsert   = @IsInsert2

        INSERT SUserInterface.GridViewColumnDefinitions
              (
                RowStatus,
                Guid,
                Name,
                ColumnOrder,
                GridViewDefinitionId,
                IsPrimaryKey,
                IsHidden,
                IsFiltered,
                IsCombo,
                IsLongitude,
                IsLatitude,
				LanguageLabelId
              )
        VALUES
            (
              1,	-- RowStatus - tinyint
              @NewID1,	-- Guid - uniqueidentifier
              N'ID',	-- Name - nvarchar(100)
              999,	-- ColumnOrder - int
              @ID,	-- GridViewDefinitionId - int
              1,	-- IsPrimaryKey - bit
              1,	-- IsHidden - bit
              1,	-- IsFiltered - bit
              0,	-- IsCombo - bit
              0,	-- IsLongitude - bit
              0,	-- IsLatitude - bit
			  @IdLanguageLabel
            ),
            (
              1,	-- RowStatus - tinyint
              @NewID2,	-- Guid - uniqueidentifier
              N'Guid',	-- Name - nvarchar(100)
              0,	-- ColumnOrder - int
              @ID,	-- GridViewDefinitionId - int
              0,	-- IsPrimaryKey - bit
              1,	-- IsHidden - bit
              0,	-- IsFiltered - bit
              0,	-- IsCombo - bit
              0,	-- IsLongitude - bit
              0,	-- IsLatitude - bit
			  @GuidLanguageLabel
            )
      END
    ELSE
      BEGIN
        UPDATE  SUserInterface.GridViewDefinitions
        SET     [LanguageLabelId] = @LanguageLabelID,
				[Code] = @Code,
                [RowStatus] = @RowStatus,
                [GridDefinitionId] = @GridDefinitionID,
                [DetailPageUri] = @DetailPageUri,
                [SqlQuery] = @SqlQuery,
                [DefaultSortColumnName] = @DefaultSortColumnName,
                [SecurableCode] = @SecurableCode,
                [DisplayOrder] = @DisplayOrder,
                [DisplayGroupName] = @DisplayGroupName,
                [MetricSqlQuery] = @MetricSqlQuery,
                [ShowMetric] = @ShowMetric,
                [IsDetailWindowed] = @IsDetailWindowed,
                [EntityTypeID] = @EntityTypeID,
                MetricTypeID = @MetricTypeID,
                MetricMin = @MetricMin,
                MetricMax = @MetricMax,
                MetricMinorUnit = @MetricMinorUnit,
                MetricMajorUnit = @MetricMajorUnit,
                MetricStartAngle = @MetricStartAngle,
                MetricEndAngle = @MetricEndAngle,
                MetricReversed = @MetricReversed,
                MetricRange1Min = @MetricRange1Min,
                MetricRange1Max = @MetricRange1Max,
                MetricRange1ColourHex = @MetricRange1ColourHex,
                MetricRange2Min = @MetricRange2Min,
                MetricRange2Max = @MetricRange2Max,
                MetricRange2ColourHex = @MetricRange2ColourHex,
                DrawerIconId = @DrawerIconId,
                IsDefaultSortDescending = @IsDefaultSortDescending,
                AllowNew = @AllowNew,
                AllowExcelExport = @AllowExcelExport,
                AllowPdfExport = @AllowPdfExport,
                AllowCsvExport = @AllowCsvExport,
				GridViewTypeId = @GridViewTypeID,
				AllowBulkChange = @AllowBulkChange,
				ShowOnMobile = @ShowOnMobile
        WHERE
          ([Guid] = @Guid)
      END
  END




GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SCore].[EntityPropertyGroupUpsert]
--
GO
CREATE OR ALTER PROCEDURE [SCore].[EntityPropertyGroupUpsert]
	(	@Name NVARCHAR(250),
		@RowStatus TINYINT,
		@IsHidden BIT,
		@SortOrder INT,
		@LanguageLabelGuid UNIQUEIDENTIFIER,
		@EntityTypeGuid UNIQUEIDENTIFIER,
		@PropertyGroupLayoutGuid UNIQUEIDENTIFIER,
		@ShowOnMobile BIT,		
		@IsCollapsable BIT,
		@IsDefaultCollapsed BIT,
		@IsDefaultCollapsed_Mobile BIT,
		@Guid UNIQUEIDENTIFIER OUT
	)
AS
BEGIN
	SET NOCOUNT ON 

	DECLARE @EntityTypeID		   INT,
			@LanguageLabelID	   INT,
			@PropertyGroupLayoutID INT;

	SELECT	@EntityTypeID = ID
	FROM	SCore.EntityTypes
	WHERE	(Guid = @EntityTypeGuid);

	SELECT	@LanguageLabelID = ID
	FROM	SCore.LanguageLabels
	WHERE	(Guid = @LanguageLabelGuid);

	SELECT	@PropertyGroupLayoutID = ID
	FROM	SUserInterface.PropertyGroupLayouts
	WHERE	(Guid = @PropertyGroupLayoutGuid);

	DECLARE @IsInsert BIT = 0;
	EXEC SCore.UpsertDataObject @Guid = @Guid,					-- uniqueidentifier
								@SchemeName = N'SCore',			-- nvarchar(255)
								@ObjectName = N'EntityPropertyGroups',		-- nvarchar(255)
								@IsInsert = @IsInsert OUTPUT;	-- bit

	IF (@IsInsert = 1)
	BEGIN
		SET @RowStatus = 1;

		INSERT	SCore.EntityPropertyGroups
			 (Guid, Name, RowStatus, IsHidden, SortOrder, LanguageLabelID, EntityTypeID, PropertyGroupLayoutID, ShowOnMobile, IsCollapsable, IsDefaultCollapsed, IsDefaultCollapsed_Mobile)
		VALUES
			 (
				 @Guid,
				 @Name,
				 @RowStatus,
				 @IsHidden,
				 @SortOrder,
				 @LanguageLabelID,
				 @EntityTypeID,
				 @PropertyGroupLayoutID,
				 @ShowOnMobile,
				 @IsCollapsable,
				 @IsDefaultCollapsed,
				 @IsDefaultCollapsed_Mobile
			 );


	END;
	ELSE
	BEGIN
		UPDATE	SCore.EntityPropertyGroups
		SET		Name = @Name,
				RowStatus = @RowStatus,
				IsHidden = @IsHidden,
				SortOrder = @SortOrder,
				LanguageLabelID = @LanguageLabelID,
				EntityTypeID = @EntityTypeID,
				PropertyGroupLayoutID = @PropertyGroupLayoutID,
				ShowOnMobile = @ShowOnMobile,
				IsCollapsable = @IsCollapsable,
				IsDefaultCollapsed = @IsDefaultCollapsed,
				IsDefaultCollapsed_Mobile = @IsDefaultCollapsed_Mobile
		WHERE	(Guid = @Guid);
	END;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

