--
-- Create or alter function [SCore].[tvf_GetScheduledActivities]
--
GO

/*
	[*] Returns upcoming scheduled activities for a user.
	[*] Used in the "Scheduler" to popuate the calendar.
*/
CREATE OR ALTER FUNCTION [SCore].[tvf_GetScheduledActivities] 
(
	@UserId INT
)
RETURNS TABLE
AS
RETURN
(
   SELECT 
	root_hobt.SurveyorID AS UserId,
	root_hobt.Date AS StartDate,
	root_hobt.EndDate,
	root_hobt.Title,
	j.Number as JobNumber,
	root_hobt.Notes AS Note
FROM 
	SJob.Activities root_hobt
LEFT JOIN SJob.Jobs AS j ON j.ID = root_hobt.JobID
WHERE 
	(root_hobt.SurveyorID = @UserId AND root_hobt.ActivityStatusID = 2) --Tentative
);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[CurrentScheduledWork]
--
GO

CREATE OR ALTER FUNCTION [SJob].[CurrentScheduledWork]
(
	@UserId INT
)
RETURNS TABLE
	   --WITH SCHEMABINDING
AS RETURN
SELECT	j.ID,
		j.Guid,
		a.RowVersion,
		a.RowStatus,
		j.Number AS JobNumber,
		client.Name AS ClientName,
		prop.FormattedAddressComma AS PropertyAddress,
		a.Date AS StartDateTime,
		a.EndDate AS EndDateTime,
		a.Title ActivityTitle,
		aty.Name   AS ActivityType,
		ast.Name   AS ActivityStatus,
		i.FullName AS SurveyorName,
		ast.SortOrder AS SortPriority
FROM	SJob.Activities		AS a
JOIN	SJob.ActivityStatus AS ast ON (ast.ID = a.ActivityStatusID)
JOIN	SJob.ActivityTypes	AS aty ON (aty.ID = a.ActivityTypeID)
JOIN	SJob.Jobs			AS j ON (j.ID	  = a.JobID)
JOIN	SJob.Properties prop ON (prop.ID = j.UprnID)
JOIN	SCrm.Accounts client ON (client.ID = j.ClientAccountID)
JOIN	SCore.Identities	AS i ON (i.ID	  = a.SurveyorID)
WHERE	(aty.IsScheduleItem = 1)
	AND (a.SurveyorID = @UserId)
	AND	(a.Date BETWEEN DATEADD (DAY, -7, GETUTCDATE()) AND DATEADD (DAY, +7, GETUTCDATE()))
	AND (a.RowStatus NOT IN (0, 254))

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Commit Transaction
--
IF @@TRANCOUNT>0 COMMIT TRANSACTION
GO

--
-- Create full-text index on table [SCrm].[Accounts]
--
CREATE FULLTEXT INDEX
  ON [SCrm].[Accounts]([Name] LANGUAGE 1033)
  KEY INDEX [PK_Accounts]
  ON [AccountName]
  WITH CHANGE_TRACKING AUTO, STOPLIST Honorifics
GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

--
-- Set NOEXEC to off
--
SET NOEXEC OFF
GO